from __future__ import annotations

import argparse
import json
import os
import sys
import tempfile
import threading
import time

from pydbus import SessionBus
from gi.repository import GLib

KWIN_SERVICE     = "org.kde.KWin"
SCRIPTING_PATH   = "/Scripting"
RECEIVER_SERVICE = "org.probe.KWinPropTest"
RECEIVER_PATH    = "/Receiver"
RECEIVER_IFACE   = "org.probe.KWinPropTest"

RECEIVER_XML = f"""
<node>
  <interface name='{RECEIVER_IFACE}'>
    <method name='receiveResult'>
      <arg type='s' name='test_name' direction='in'/>
      <arg type='s' name='json_data' direction='in'/>
    </method>
  </interface>
</node>
"""


class C:
    _t     = sys.stdout.isatty()
    BOLD   = "\033[1m"  if _t else ""
    CYAN   = "\033[36m" if _t else ""
    GREEN  = "\033[32m" if _t else ""
    YELLOW = "\033[33m" if _t else ""
    RED    = "\033[31m" if _t else ""
    RESET  = "\033[0m"  if _t else ""

def info(m):  print(f"{C.CYAN}[INFO ] {C.RESET}{m}")
def ok(m):    print(f"{C.GREEN}[OK   ] {C.RESET}{m}")
def warn(m):  print(f"{C.YELLOW}[WARN ] {C.RESET}{m}")
def error(m): print(f"{C.RED}[ERROR] {C.RESET}{m}", file=sys.stderr)
def head(m):  print(f"\n{C.BOLD}{C.CYAN}{m}{C.RESET}")
def rline(label, value, good=True):
    c = C.GREEN if good else C.RED
    m = "✓" if good else "✗"
    print(f"  {c}{m}{C.RESET}  {label:<48} {value!r}")


class Receiver:
    dbus = RECEIVER_XML
    def __init__(self):
        self._results: dict = {}
        self._events:  dict = {}
        self._lock = threading.Lock()
    def expect(self, name):
        ev = threading.Event()
        with self._lock: self._events[name] = ev
        return ev
    def receiveResult(self, test_name, json_data):
        try:    data = json.loads(json_data)
        except: data = {"parseError": json_data[:300]}
        with self._lock:
            self._results[test_name] = data
            ev = self._events.get(test_name)
        if ev: ev.set()
    def get(self, name):
        with self._lock: return self._results.get(name)


class ScriptRunner:
    def __init__(self, scripting, receiver):
        self.scripting = scripting
        self.receiver  = receiver

    def run(self, name, js_body, timeout=6.0):
        js = f"""
var _s="{RECEIVER_SERVICE}",_p="{RECEIVER_PATH}",_i="{RECEIVER_IFACE}",_n="{name}";
function send(d){{callDBus(_s,_p,_i,"receiveResult",_n,JSON.stringify(d));}}
try{{ {js_body} }}catch(e){{send({{fatalError:String(e)}});}}
"""
        fd, path = tempfile.mkstemp(suffix=".js", prefix=f"kwin_pt_{name}_")
        os.close(fd)
        ev = self.receiver.expect(name)
        sid = None
        try:
            with open(path, "w") as f: f.write(js)
            sid = self.scripting.loadScript(path)
            self.scripting.start()
        except Exception as exc:
            os.unlink(path)
            return {"loadError": str(exc)}
        ev.wait(timeout=timeout)
        try:
            if sid is not None: self.scripting.unloadScript(str(sid))
        except: pass
        try: os.unlink(path)
        except: pass
        r = self.receiver.get(name)
        return r if r is not None else {"timeout": True}


TEST_UUID = "test-kwinlib-a3f2b8c1-4d99-87ce"


def test_setproperty_write_read(runner: ScriptRunner, window_id: str) -> dict:
    """
    Test 1: write a property with setProperty(), read it back in the same
    script execution.  Confirms the API is available at all.
    """
    head("Test 1 — setProperty() write + immediate read (same script)")
    bare = window_id.strip("{}")

    result = runner.run("prop_write_read", f"""
var targetId = "{bare}";
var testUuid = "{TEST_UUID}";
var wins     = workspace.windowList();
var w        = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === targetId) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{ send({{error: "window not found"}}); }}

var results = {{}};

// Test: does setProperty exist as a function?
results.setPropertyExists = (typeof w.setProperty === "function");
results.propertyExists    = (typeof w.property    === "function");

if (!results.setPropertyExists) {{
    send({{error: "setProperty is not a function on window object",
           results: results}});
}}

// Write the property
try {{
    var writeReturn = w.setProperty("kwinlib_uuid", testUuid);
    results.writeReturn = String(writeReturn);
    results.writeError  = null;
}} catch(e) {{
    results.writeReturn = null;
    results.writeError  = String(e);
}}

// Read it back immediately
try {{
    var readBack = w.property("kwinlib_uuid");
    results.readBack      = String(readBack);
    results.readBackType  = typeof readBack;
    results.roundTripOk   = (String(readBack) === testUuid);
}} catch(e) {{
    results.readBack    = null;
    results.readError   = String(e);
    results.roundTripOk = false;
}}

// Also check that a non-existent property returns something sensible
try {{
    var missing = w.property("kwinlib_nonexistent_xyz");
    results.missingPropValue = String(missing);
    results.missingPropType  = typeof missing;
}} catch(e) {{
    results.missingPropError = String(e);
}}

send({{results: results}});
""")

    if "fatalError" in result:
        error(f"Fatal: {result['fatalError']}")
        return result
    if "error" in result:
        warn(f"Error: {result['error']}")
        if "results" in result:
            r = result["results"]
            rline("setProperty is a function",
                  r.get("setPropertyExists"), good=bool(r.get("setPropertyExists")))
            rline("property is a function",
                  r.get("propertyExists"), good=bool(r.get("propertyExists")))
        return result

    r = result.get("results", {})
    rline("setProperty is a function",
          r.get("setPropertyExists"), good=bool(r.get("setPropertyExists")))
    rline("property is a function",
          r.get("propertyExists"),    good=bool(r.get("propertyExists")))

    if r.get("writeError"):
        rline("setProperty('kwinlib_uuid', value) — write",
              f"ERROR: {r['writeError']}", good=False)
    else:
        rline("setProperty('kwinlib_uuid', value) — write",
              f"returned {r.get('writeReturn')!r}", good=True)

    if r.get("readError"):
        rline("property('kwinlib_uuid') — read back",
              f"ERROR: {r['readError']}", good=False)
    else:
        rline("property('kwinlib_uuid') — read back",
              r.get("readBack"), good=bool(r.get("roundTripOk")))
        rline("Round-trip value matches written value",
              r.get("roundTripOk"), good=bool(r.get("roundTripOk")))

    info(f"  Missing property returns: "
         f"{r.get('missingPropValue')!r}  "
         f"(type: {r.get('missingPropType')})")

    return result


def test_setproperty_cross_script(runner: ScriptRunner, window_id: str) -> dict:
    """
    Test 2: write in one script load, read back in a SEPARATE script load.
    This is the critical test — confirms the property survives between
    distinct script executions (i.e., is truly on the QObject, not in
    script-local state).
    """
    head("Test 2 — Property persistence across separate script loads")
    bare = window_id.strip("{}")

    # Script A: write the property
    write_result = runner.run("prop_cross_write", f"""
var targetId = "{bare}";
var testUuid = "{TEST_UUID}-cross";
var wins     = workspace.windowList();
var w        = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === targetId) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{ send({{error: "window not found"}}); }}
try {{
    w.setProperty("kwinlib_uuid_cross", testUuid);
    send({{wrote: true, value: testUuid}});
}} catch(e) {{
    send({{wrote: false, error: String(e)}});
}}
""")

    if not write_result.get("wrote"):
        warn(f"Write step failed: {write_result}")
        return write_result

    ok(f"  Script A wrote property: {write_result.get('value')!r}")

    # Small gap to ensure first script is fully unloaded
    time.sleep(0.3)

    # Script B: read the property back (completely separate script load)
    read_result = runner.run("prop_cross_read", f"""
var targetId   = "{bare}";
var expectUuid = "{TEST_UUID}-cross";
var wins       = workspace.windowList();
var w          = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === targetId) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{ send({{error: "window not found"}}); }}
try {{
    var readBack = w.property("kwinlib_uuid_cross");
    send({{
        readBack:    String(readBack),
        expected:    expectUuid,
        persisted:   String(readBack) === expectUuid,
    }});
}} catch(e) {{
    send({{error: String(e)}});
}}
""")

    if "error" in read_result:
        rline("Property readable from second script load",
              f"ERROR: {read_result['error']}", good=False)
        return read_result

    persisted = bool(read_result.get("persisted"))
    rline("Property readable from second script load",
          read_result.get("readBack"), good=persisted)
    rline("Value matches what was written",
          persisted, good=persisted)

    if persisted:
        ok("CONFIRMED: Qt dynamic properties persist on window QObjects "
           "between separate script executions.")
        ok("The session UUID tracking approach is viable.")
    else:
        warn("Property did NOT persist across script loads.")
        warn("Will need an alternative tracking approach (state file).")

    return read_result


def test_enumerate_with_property(runner: ScriptRunner, window_id: str) -> dict:
    """
    Test 3: enumerate all windows and find one by its kwinlib_uuid property.
    This validates the lookup pattern the realign utility would use.
    """
    head("Test 3 — Find window by kwinlib_uuid property (lookup pattern)")
    bare = window_id.strip("{}")

    result = runner.run("prop_lookup", f"""
var targetId = "{bare}";
var testUuid = "{TEST_UUID}-lookup";

// First: stamp the UUID on the target window
var wins = workspace.windowList();
var w    = null;
for (var i = 0; i < wins.length; i++) {{
    if (String(wins[i].internalId).replace(/[{{}}]/g,"") === targetId) {{
        w = wins[i]; break;
    }}
}}
if (!w) {{ send({{error: "target window not found"}}); }}
w.setProperty("kwinlib_uuid", testUuid);

// Second: find it back by scanning all windows for the UUID
// (simulating what the realign utility does — it only knows the UUID,
// not the internalId)
var found    = null;
var searched = 0;
var wins2    = workspace.windowList();
for (var i = 0; i < wins2.length; i++) {{
    searched++;
    try {{
        var v = wins2[i].property("kwinlib_uuid");
        if (String(v) === testUuid) {{
            found = wins2[i];
            break;
        }}
    }} catch(e) {{}}
}}

if (found) {{
    send({{
        found:        true,
        searched:     searched,
        internalId:   String(found.internalId),
        resourceClass: String(found.resourceClass || ""),
        caption:      String(found.caption || ""),
        matchConfirmed: (String(found.internalId).replace(/[{{}}]/g,"") === targetId),
    }});
}} else {{
    send({{found: false, searched: searched}});
}}
""")

    if "fatalError" in result or "error" in result:
        error(f"Test 3 failed: {result.get('fatalError') or result.get('error')}")
        return result

    if result.get("found"):
        ok(f"Window found by UUID scan (searched {result.get('searched')} windows)")
        rline("internalId matches original target",
              result.get("matchConfirmed"), good=bool(result.get("matchConfirmed")))
        info(f"  resourceClass : {result.get('resourceClass')!r}")
        info(f"  internalId    : {result.get('internalId')}")
    else:
        warn(f"Window NOT found by UUID scan "
             f"(searched {result.get('searched')} windows)")

    return result


def main():
    parser = argparse.ArgumentParser(
        prog="kwin_property_test.py",
        description="Test Qt dynamic property persistence on KWin window objects.",
    )
    parser.add_argument("--id", dest="window_id", required=True, metavar="UUID",
        help="internalId of any open window (from kwin_probe.py)")
    args = parser.parse_args()

    head("═══ KWin Qt Dynamic Property Test ══════════════════════════════")
    info(f"Target window : {args.window_id}")
    info(f"Test UUID     : {TEST_UUID}")

    bus      = SessionBus()
    receiver = Receiver()
    try:
        reg = bus.publish(RECEIVER_SERVICE, (RECEIVER_PATH, receiver))
    except Exception as exc:
        error(f"Cannot publish receiver: {exc}"); sys.exit(1)

    loop = GLib.MainLoop()
    threading.Thread(target=loop.run, daemon=True).start()
    scripting = bus.get(KWIN_SERVICE, SCRIPTING_PATH)
    runner    = ScriptRunner(scripting, receiver)

    try:
        r1 = test_setproperty_write_read(runner, args.window_id)
        r2 = test_setproperty_cross_script(runner, args.window_id)
        r3 = test_enumerate_with_property(runner, args.window_id)

        head("═══ Summary ═════════════════════════════════════════════════════")
        t1 = r1.get("results", {}).get("roundTripOk", False)
        t2 = r2.get("persisted", False)
        t3 = r3.get("found", False)
        rline("Test 1: setProperty/property API available",    t1, good=t1)
        rline("Test 2: Property persists across script loads", t2, good=t2)
        rline("Test 3: Window findable by UUID scan",          t3, good=t3)

        if t1 and t2 and t3:
            print()
            ok("All tests passed.")
            ok("Session UUID tracking via Qt dynamic properties is VIABLE.")
            ok("Plan: stamp kwinlib_uuid at restore time, read at realign time.")
        elif t1 and not t2:
            print()
            warn("Property API works but does NOT persist across script loads.")
            warn("Will use a state file (uuid → internalId map) instead,")
            warn("updated each time a new window is detected via windowAdded.")
        else:
            print()
            warn("setProperty/property not available in this KWin version.")
            warn("Will fall back to signature-based matching (resourceClass +")
            warn("screen + approximate geometry) for the realign utility.")

    finally:
        loop.quit()
        try: reg.unpublish()
        except: pass

    head("═══ Done ════════════════════════════════════════════════════════")


if __name__ == "__main__":
    main()
